import { useMemo, useState } from "react";
import { motion } from "framer-motion";
import SEOHead from "@/components/SEOHead";
import AdPlaceholder from "@/components/AdPlaceholder";
import RelatedTools from "@/components/RelatedTools";
import ShareButton from "@/components/ShareButton";
import FAQItem from "@/components/FAQItem";

const FAQS = [
  { q: "How do you solve a right triangle?", a: "A right triangle can be solved from two known values by using the Pythagorean theorem and trigonometric ratios. Once two sides or one side plus one acute angle are known, the remaining values can be calculated." },
  { q: "What is SOH CAH TOA?", a: "SOH CAH TOA remembers the trig ratios: sine = opposite/hypotenuse, cosine = adjacent/hypotenuse, and tangent = opposite/adjacent." },
  { q: "How do you find an angle in a right triangle?", a: "Use inverse trigonometric functions. For example, if you know opposite and adjacent sides, angle = arctan(opposite / adjacent)." },
  { q: "What is the hypotenuse?", a: "The hypotenuse is the longest side of a right triangle and sits opposite the 90-degree angle." },
  { q: "How do you calculate the area of a right triangle?", a: "The area is one half times the two legs: A = (a x b) / 2, where a and b are the perpendicular sides." },
];

type Mode = "legs" | "legHyp" | "legAngle";
const fmt = (value: number) => Number.isFinite(value) ? Number(value.toFixed(4)).toLocaleString() : "Invalid";
const deg = (rad: number) => rad * 180 / Math.PI;
const rad = (degValue: number) => degValue * Math.PI / 180;

export default function RightTriangleCalculator() {
  const [mode, setMode] = useState<Mode>("legs");
  const [a, setA] = useState(3);
  const [b, setB] = useState(4);
  const [c, setC] = useState(5);
  const [angleA, setAngleA] = useState(36.87);
  const inputClass = "w-full px-3 py-2 rounded-xl border border-input bg-background text-foreground text-lg font-bold focus:outline-none focus:ring-2 focus:ring-primary/40 transition-all";

  const result = useMemo(() => {
    let legA = a, legB = b, hyp = c, step = "";
    if (mode === "legs") { hyp = Math.sqrt(a * a + b * b); step = `c = sqrt(${a}^2 + ${b}^2) = ${fmt(hyp)}.`; }
    if (mode === "legHyp") { legB = Math.sqrt(Math.max(0, c * c - a * a)); hyp = c; step = `b = sqrt(${c}^2 - ${a}^2) = ${fmt(legB)}.`; }
    if (mode === "legAngle") { legB = a * Math.tan(rad(angleA)); hyp = a / Math.cos(rad(angleA)); step = `Using tan(A) = opposite/adjacent, b = ${a} x tan(${angleA}) = ${fmt(legB)}. c = ${a} / cos(${angleA}) = ${fmt(hyp)}.`; }
    const angleOne = deg(Math.atan2(legB, legA));
    const angleTwo = 90 - angleOne;
    const area = (legA * legB) / 2;
    const perimeter = legA + legB + hyp;
    return { legA, legB, hyp, angleOne, angleTwo, area, perimeter, step };
  }, [mode, a, b, c, angleA]);

  return (
    <>
      <SEOHead title="Free Right Triangle Calculator Online - Solve Any Right Triangle Completely Instantly | CalcHive" description="Free online right triangle calculator. Solve any right triangle completely from any two values - find all sides, angles, area and perimeter instantly. 100% free for students, no signup required." canonical="/right-triangle-calculator" keywords="free right triangle calculator, right triangle solver free online, find all sides of right triangle free, trigonometry triangle calculator free, right angle triangle calculator free" category="Math Calculators" faqs={FAQS} />
      <main className="max-w-3xl mx-auto px-4 sm:px-6 py-10">
        <div className="mb-8"><span className="text-xs font-semibold uppercase tracking-widest text-amber-600 dark:text-amber-400 bg-amber-50 dark:bg-amber-950/50 px-3 py-1 rounded-full mb-4 inline-block">Math</span><h1 className="text-3xl sm:text-4xl font-extrabold text-foreground tracking-tight mb-3">Free Right Triangle Calculator Online</h1><p className="text-muted-foreground leading-relaxed">Use this free right triangle calculator to solve sides, angles, area, perimeter, and hypotenuse from two known values.</p></div>
        <AdPlaceholder size="banner" className="mb-8" />
        <section className="bg-card border border-border rounded-2xl p-6 sm:p-8 shadow-md mb-8">
          <div className="grid grid-cols-1 sm:grid-cols-3 gap-4 mb-8">
            <div><label htmlFor="mode" className="text-sm font-semibold text-foreground block mb-2">Known values</label><select id="mode" value={mode} onChange={(event) => setMode(event.target.value as Mode)} className={inputClass}><option value="legs">Two legs</option><option value="legHyp">One leg and hypotenuse</option><option value="legAngle">One leg and acute angle</option></select></div>
            <div><label htmlFor="leg-a" className="text-sm font-semibold text-foreground block mb-2">Leg a</label><input id="leg-a" type="number" min="0" inputMode="decimal" value={a} onChange={(event) => setA(Number(event.target.value))} className={inputClass} /></div>
            {mode === "legs" && <div><label htmlFor="leg-b" className="text-sm font-semibold text-foreground block mb-2">Leg b</label><input id="leg-b" type="number" min="0" inputMode="decimal" value={b} onChange={(event) => setB(Number(event.target.value))} className={inputClass} /></div>}
            {mode === "legHyp" && <div><label htmlFor="hyp" className="text-sm font-semibold text-foreground block mb-2">Hypotenuse c</label><input id="hyp" type="number" min="0" inputMode="decimal" value={c} onChange={(event) => setC(Number(event.target.value))} className={inputClass} /></div>}
            {mode === "legAngle" && <div><label htmlFor="angle-a" className="text-sm font-semibold text-foreground block mb-2">Angle A (degrees)</label><input id="angle-a" type="number" min="0" max="90" inputMode="decimal" value={angleA} onChange={(event) => setAngleA(Number(event.target.value))} className={inputClass} /></div>}
          </div>
          <motion.div key={`${mode}-${a}-${b}-${c}-${angleA}`} initial={{ opacity: 0.7, y: 4 }} animate={{ opacity: 1, y: 0 }} transition={{ duration: 0.25 }}>
            <div className="bg-gradient-to-br from-amber-500 to-amber-700 rounded-2xl p-6 text-center shadow-lg"><p className="text-xs font-semibold uppercase tracking-widest text-white/70 mb-1">Hypotenuse</p><p className="text-6xl font-black text-white tracking-tight" data-testid="result-right-triangle">{fmt(result.hyp)}</p></div>
            <div className="grid grid-cols-2 sm:grid-cols-3 gap-3 mt-4">{[["Leg a", result.legA], ["Leg b", result.legB], ["Angles", `${fmt(result.angleOne)} deg / ${fmt(result.angleTwo)} deg / 90 deg`], ["Area", result.area], ["Perimeter", result.perimeter], ["Hypotenuse", result.hyp]].map(([label, val]) => <div key={label as string} className="bg-accent/60 border border-border rounded-xl p-3 text-center"><p className="text-xs text-muted-foreground font-medium">{label}</p><p className="text-sm font-extrabold text-foreground">{typeof val === "number" ? fmt(val) : val}</p></div>)}</div>
            <div className="mt-4 bg-accent/60 border border-border rounded-xl p-4"><p className="text-xs font-bold uppercase tracking-wide text-muted-foreground mb-2">Step by step</p><p className="text-sm text-foreground" data-testid="result-steps">{result.step}</p></div>
          </motion.div>
        </section>
        <ShareButton />
        <section className="mb-8 space-y-6"><h2 className="text-2xl font-bold text-foreground">How to Solve Any Right Triangle Completely for Free</h2><p className="text-muted-foreground leading-relaxed">Choose the known values and this right triangle solver free online tool calculates the remaining sides, angles, area, and perimeter.</p><h2 className="text-2xl font-bold text-foreground">How to Find All Sides and Angles of a Right Triangle</h2><p className="text-muted-foreground leading-relaxed">The calculator combines trigonometry ratios with the Pythagorean theorem to solve the full triangle.</p><h2 className="text-2xl font-bold text-foreground">Free Trigonometry Right Triangle Tool for Students</h2><p className="text-muted-foreground leading-relaxed">Use this trigonometry triangle calculator free for homework, angle checks, and right-triangle geometry problems.</p></section>
        <section className="mb-8"><h3 className="text-xl font-bold text-foreground mb-4">Frequently Asked Questions</h3><div className="space-y-3">{FAQS.map((faq) => <FAQItem key={faq.q} q={faq.q} a={faq.a} />)}</div></section>
        <AdPlaceholder size="rectangle" className="mx-auto mb-8" />
        <RelatedTools exclude="/right-triangle-calculator" headingLevel="h3" />
      </main>
    </>
  );
}


